pipeline.evaluate:
(async () => {
  const keywords = '${{ args.query }}'.split(',').map(k => k.trim()).filter(Boolean);
  const maxAccepts = parseInt('${{ args.max }}');
  const results = [];
  let acceptCount = 0;

  const convs = Array.from(document.querySelectorAll('[data-testid="conversation"]'));
  if (convs.length === 0) return [{ index: 1, status: 'info', user: 'System', message: 'No message requests found' }];

  for (let i = 0; i < Math.min(convs.length, maxAccepts); i++) {
    const conv = convs[i];
    const text = conv.innerText || '';
    const previewMatch = keywords.some(k => text.includes(k));
    if (!previewMatch) continue;

    conv.click();
    await new Promise(r => setTimeout(r, 2000));

    const chatArea = document.querySelector('[data-testid="DmScrollerContainer"]') || document.querySelector('main');
    const chatText = chatArea ? chatArea.innerText : '';
    const matchedKw = keywords.filter(k => chatText.includes(k));
    if (matchedKw.length === 0) continue;

    const allBtns = Array.from(document.querySelectorAll('[role="button"]'));
    const acceptBtn = allBtns.find(btn => {
      const t = btn.innerText.trim().toLowerCase();
      return t === 'accept' || t === '接受';
    });

    if (acceptBtn) {
      acceptBtn.click();
      await new Promise(r => setTimeout(r, 2000));
      acceptCount++;
      results.push({ index: acceptCount, status: 'accepted', user: 'User', message: 'Matched: ' + matchedKw.join(', ') });
    }

    if (acceptCount >= maxAccepts) break;
  }

  if (results.length === 0) {
    return [{ index: 0, status: 'info', user: 'System', message: 'No requests matched keywords' }];
  }
  return results;
})()
